import { readFileSync, readdirSync, writeFileSync } from 'node:fs'
import path from 'node:path'

const directory = path.resolve('crates/scope-core/src/db')
const files = readdirSync(directory)
  .filter((name) => name.endsWith('.rs'))
  .map((name) => path.join(directory, name))

for (const file of files) {
  const before = readFileSync(file, 'utf8')
  const after = postgresOnly(before)
  if (after !== before) {
    writeFileSync(file, after)
  }
}

function postgresOnly(source) {
  const marker = 'match self.inner.as_ref() {'
  let cursor = 0
  while (true) {
    const start = source.indexOf(marker, cursor)
    if (start === -1) return source
    const matchOpen = source.indexOf('{', start + marker.length - 1)
    const matchClose = matchingBrace(source, matchOpen)
    const matchBody = source.slice(matchOpen + 1, matchClose)
    if (!matchBody.includes('MetadataStoreInner::Memory')) {
      cursor = matchClose + 1
      continue
    }

    const postgres = source.indexOf('MetadataStoreInner::Postgres', matchOpen)
    const arrow = source.indexOf('=>', postgres)
    const pattern = source
      .slice(postgres + 'MetadataStoreInner::Postgres'.length, arrow)
      .trim()
    const bodyOpen = nextNonWhitespace(source, arrow + 2)
    if (source[bodyOpen] !== '{') {
      throw new Error(`${fileLabel(source, start)}: Postgres arm is not a block`)
    }
    const bodyClose = matchingBrace(source, bodyOpen)
    const remainder = source.slice(bodyClose + 1, matchClose)
    if (!remainder.includes('MetadataStoreInner::Memory')) {
      throw new Error(`${fileLabel(source, start)}: Memory arm was not after Postgres arm`)
    }

    const lineStart = source.lastIndexOf('\n', start) + 1
    const indent = source.slice(lineStart, start)
    const body = source.slice(bodyOpen + 1, bodyClose).replace(/^\n/, '').trimEnd()
    const replacement =
      `let MetadataStoreInner::Postgres ${pattern} = self.inner.as_ref();\n` +
      body.replaceAll(`\n${indent}    `, `\n${indent}`)
    source = source.slice(0, start) + replacement + source.slice(matchClose + 1)
    cursor = start + replacement.length
  }
}

function nextNonWhitespace(source, start) {
  let index = start
  while (/\s/.test(source[index])) index += 1
  return index
}

function matchingBrace(source, open) {
  let depth = 0
  let state = 'normal'
  let blockDepth = 0
  let rawHashes = 0

  for (let index = open; index < source.length; index += 1) {
    const current = source[index]
    const next = source[index + 1]

    if (state === 'line') {
      if (current === '\n') state = 'normal'
      continue
    }
    if (state === 'block') {
      if (current === '/' && next === '*') {
        blockDepth += 1
        index += 1
      } else if (current === '*' && next === '/') {
        blockDepth -= 1
        index += 1
        if (blockDepth === 0) state = 'normal'
      }
      continue
    }
    if (state === 'string' || state === 'char') {
      if (current === '\\') {
        index += 1
      } else if (
        (state === 'string' && current === '"') ||
        (state === 'char' && current === "'")
      ) {
        state = 'normal'
      }
      continue
    }
    if (state === 'raw') {
      if (current === '"' && source.slice(index + 1, index + 1 + rawHashes) === '#'.repeat(rawHashes)) {
        index += rawHashes
        state = 'normal'
      }
      continue
    }

    if (current === '/' && next === '/') {
      state = 'line'
      index += 1
      continue
    }
    if (current === '/' && next === '*') {
      state = 'block'
      blockDepth = 1
      index += 1
      continue
    }
    if (current === '"') {
      state = 'string'
      continue
    }
    if (current === "'") {
      state = 'char'
      continue
    }
    const raw = source.slice(index).match(/^(?:b)?r(#+)?"/)
    if (raw) {
      rawHashes = raw[1]?.length ?? 0
      index += raw[0].length - 1
      state = 'raw'
      continue
    }
    if (current === '{') depth += 1
    if (current === '}') {
      depth -= 1
      if (depth === 0) return index
    }
  }
  throw new Error(`unmatched brace at ${open}`)
}

function fileLabel(source, index) {
  return `line ${source.slice(0, index).split('\n').length}`
}

