  color: var(--accent);
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
}

ul,
ol {
  margin: 12px 0 0;
  padding-left: 18px;
}

li {
  margin: 8px 0;
  color: var(--muted);
  font-size: 16px;
  line-height: 1.5;
  text-wrap: pretty;
}

strong {
  color: var(--ink);
}

code {
  border: 1px solid var(--soft-line);
  background: var(--surface);
  padding: 1px 5px;
