  display: grid;
  grid-template-columns: 150px minmax(0, 1fr);
  gap: 16px;
  align-items: start;
  border-top: 1px solid var(--line);
  padding-top: 14px;
}

.flow-row:first-child {
  border-top: 0;
  padding-top: 0;
}

.flow-title {
  font-size: 13px;
  font-weight: 800;
  text-transform: uppercase;
