    sans-serif;
  font-size: 14px;
}

.matrix th,
.matrix td {
  border-top: 1px solid var(--line);
  padding: 13px 10px;
  text-align: left;
  vertical-align: top;
}

.matrix th {
  color: var(--ink);
  font-size: 12px;
  font-weight: 900;
  text-transform: uppercase;
}

.matrix td {
  color: var(--muted);
  line-height: 1.45;
}

.matrix tr:last-child td {
  border-bottom: 1px solid var(--line);
}

.timeline {
  display: grid;
  border-top: 1px solid var(--line);
}

.phase {
  display: grid;
  grid-template-columns: 130px minmax(0, 1fr) 210px;
  gap: 22px;
  border-bottom: 1px solid var(--line);
  padding: 18px 0;
  align-items: start;
}

.phase.phase-done {
  background: linear-gradient(90deg, var(--done-soft), transparent 42%);
