  const inserts = [];
  for (const match of source.matchAll(/\bfn\s+[A-Za-z_][A-Za-z0-9_]*\s*(?:<[^;{]*>)?\s*\(/g)) {
    const fnIndex = match.index;
    if (/async\s+$/.test(source.slice(Math.max(0, fnIndex - 12), fnIndex))) continue;
    const open = source.indexOf("{", fnIndex + match[0].length);
    if (open < 0 || source.slice(fnIndex, open).includes(";")) continue;
    const close = matchingBrace(source, open);
    if (close < 0) continue;
    if (source.slice(open, close).includes(".await")) inserts.push(fnIndex);
  }
  for (const index of inserts.reverse()) source = source.slice(0, index) + "async " + source.slice(index);
  source = source.replace(/#\[test\](\s*)async fn/g, "#[tokio::test]$1async fn");
  fs.writeFileSync(path, source);
}

