    let mut bytes = [0_u8; USER_CODE_BYTES];
    getrandom::fill(&mut bytes).map_err(|error| {
        ApiError::internal_message(format!("failed to generate login code: {error}"))
    })?;
    Ok(hex::encode_upper(bytes))
}
