import {
  HttpError,
  createApiClient,
  getCliInstallConnection,
} from '@/api/client'
import type {
  AccountSession,
  CliInstallCommands,
  HomeState,
  RepoSummary,
} from './types'

export async function loadHomeForRequest(): Promise<HomeState> {
  const cliInstallCommands = buildCliInstallCommands()
  const api = createApiClient()

  try {
    const [account, repositories] = await Promise.all([
      api.get<AccountSession>('/v1/session', { auth: 'required' }),
      api.get<RepoSummary[]>('/v1/repos', { auth: 'required' }),
    ])

    return {
      account,
      cliInstallCommands,
      error: null,
      repositories,
    }
  } catch (error) {
    if (error instanceof HttpError && error.status === 401) {
      throw new Error('Sign in required.')
    }

    return {
      account: null,
      cliInstallCommands,
      error: error instanceof Error ? error.message : 'request failed',
      repositories: [],
    }
  }
}

function buildCliInstallCommands(): CliInstallCommands {
  const baseUrl = getCliInstallConnection()
  return {
    posix: `curl -fsSL ${baseUrl}/install.sh | sh`,
    windows: `irm ${baseUrl}/install.ps1 | iex`,
  }
}
import {
  type ApiClient,
  createApiClient,
  HttpError,
} from './client'
import type {
  ProjectionPreview,
  ProjectionPreviewInput,
  ProjectionPreviewSource,
  ProjectionPreviews,
  RepoParams,
} from './types'

export async function loadProjectionPreviewsForRequest(
  data: RepoParams,
  source: ProjectionPreviewSource,
  options: { includePrivate?: boolean; api?: ApiClient } = {},
): Promise<ProjectionPreviews> {
  const api = options.api ?? createApiClient()
  const authenticated = await api.authenticated()
  const includePrivate = options.includePrivate ?? true
  const [privatePreview, publicPreview] = await Promise.all([
    authenticated && includePrivate
      ? loadProjectionPreview(api, { ...data, audience: 'private', source })
      : Promise.resolve(null),
    loadOptionalProjectionPreview(api, { ...data, audience: 'public', source }),
  ])

  return {
    private: privatePreview,
    public: publicPreview,
    source,
  }
}

async function loadProjectionPreview(
  api: ApiClient,
  data: ProjectionPreviewInput,
) {
  const query = new URLSearchParams({
    audience: data.audience,
    source: data.source,
  })

  return api.get<ProjectionPreview>(
    `/v1/repos/${data.owner}/${data.repo}/projection-preview?${query}`,
    { auth: 'optional' },
  )
}

async function loadOptionalProjectionPreview(
  api: ApiClient,
  data: ProjectionPreviewInput,
) {
  try {
    return await loadProjectionPreview(api, data)
  } catch (error) {
    if (error instanceof HttpError && [403, 404].includes(error.status)) {
      return null
    }
    throw error
  }
}
