                    path: ScopePath::parse("/README.md").unwrap(),
                    old_content: None,
                    new_content: Some(source_blob("hello")),
                },
                FileChange {
                    visibility: Visibility::Private,
                    path: ScopePath::parse("/secret.txt").unwrap(),
                    old_content: None,
                    new_content: Some(source_blob("secret")),
